# lib/blog/post.ex

defmodule Blog.Post do
  use Ecto.Schema
  import Ecto.Changeset

  schema "posts" do
    field :content, :string

    timestamps()
  end

  @doc false
  def changeset(post, attrs) do
    post
    |> cast(attrs, [:content])
    |> validate_required([:content])
  end
end


# lib/web/live/post_live.ex

defmodule Blog.PostLive do
  use Phoenix.LiveView

  def mount(_session, socket) do
    {:ok, assign(socket, :post, nil)}
  end

  def render(assigns) do
    ~L"""
      <%= raw @post.content %>
    """
  end

  def handle_event("new_post", _params, socket) do
    new_post = Blog.Post.insert_changeset(Blog.Post.changeset(%Blog.Post{}, %{content: "<p>Hello World!</p>"}))
    {:noreply, assign(socket, :post, new_post)}
  end
end


